package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testIsLineBreak_withNullCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (Character) null);
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_withLineFeedCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, '\n');
        assertTrue(result);
    }

    @Test
    void testIsLineBreak_withCarriageReturnCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, '\r');
        assertTrue(result);
    }

    @Test
    void testIsLineBreak_withNonLineBreakCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, 'a');
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_char_overload_withLineFeed() throws Exception {
        Method methodChar = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        methodChar.setAccessible(true);
        Boolean result = (Boolean) methodChar.invoke(null, '\n');
        assertTrue(result);
    }

    @Test
    void testIsLineBreak_char_overload_withCarriageReturn() throws Exception {
        Method methodChar = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        methodChar.setAccessible(true);
        Boolean result = (Boolean) methodChar.invoke(null, '\r');
        assertTrue(result);
    }

    @Test
    void testIsLineBreak_char_overload_withOtherChar() throws Exception {
        Method methodChar = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        methodChar.setAccessible(true);
        Boolean result = (Boolean) methodChar.invoke(null, 'x');
        assertFalse(result);
    }
}
